from abc import ABC, abstractmethod


class SensorAdapter(ABC):
    """Convert raw sensor output into a normalised Percept."""

    @abstractmethod
    def read(self) -> Percept:
        ...


class UserMessageAdapter(SensorAdapter):
    """Wraps incoming user text as a Percept."""

    def __init__(self, message: str):
        self._message = message

    def read(self) -> Percept:
        return Percept(
            source=SensorType.USER_MESSAGE,
            raw_value=self._message,
            features={"length": len(self._message), "text": self._message},
        )


class ToolResultAdapter(SensorAdapter):
    """Wraps a tool's JSON response as a Percept."""

    def __init__(self, tool_name: str, result: dict):
        self._tool = tool_name
        self._result = result

    def read(self) -> Percept:
        is_success = self._result.get("status") in (200, "ok", True)
        return Percept(
            source=SensorType.TOOL_RESULT,
            raw_value=self._result,
            confidence=0.99 if is_success else 0.0,
            valid=is_success,
            features=self._result.get("data", {}),
            metadata={"tool": self._tool},
        )


# Uniform interface regardless of source type
adapters: list[SensorAdapter] = [
    UserMessageAdapter("What is the temperature today?"),
    ToolResultAdapter("weather_api", {"status": 200, "data": {"temp_c": 21}}),
]
percepts = [a.read() for a in adapters]
print([p.source for p in percepts])
# [<SensorType.USER_MESSAGE: 1>, <SensorType.TOOL_RESULT: 2>]

from dataclasses import dataclass, field


@dataclass
class MultiSensorObserver:
    """
    Reads from multiple sensor adapters simultaneously and produces
    a combined percept bundle for the agent to consume.
    """

    adapters: list[SensorAdapter] = field(default_factory=list)
    max_age_ms: float = 500.0

    def observe_all(self) -> list[Percept]:
        """Read all sensors; return only valid, fresh percepts."""
        percepts = [a.read() for a in self.adapters]
        return [
            p for p in percepts
            if p.valid and p.is_fresh(self.max_age_ms)
        ]

    def observe_by_source(
        self, source: SensorType
    ) -> list[Percept]:
        """Return only percepts from the specified source type."""
        return [
            p for p in self.observe_all()
            if p.source == source
        ]

    def highest_confidence(self) -> Percept | None:
        """Return the percept the agent should trust most right now."""
        percepts = self.observe_all()
        if not percepts:
            return None
        return max(percepts, key=lambda p: p.confidence)

import pytest
import time


class TestPercept:
    def test_fresh_percept_is_fresh(self):
        p = Percept(source=SensorType.USER_MESSAGE, raw_value="hello")
        assert p.is_fresh(max_age_ms=500)

    def test_old_percept_is_stale(self):
        p = Percept(
            source=SensorType.USER_MESSAGE,
            raw_value="old",
            timestamp=time.monotonic() - 1.0,  # 1 second ago
        )
        assert not p.is_fresh(max_age_ms=500)

    def test_invalid_percept_is_not_fresh(self):
        p = Percept(source=SensorType.TOOL_RESULT, raw_value=None, valid=False)
        assert not p.is_fresh()


class TestToolResultAdapter:
    def test_success_response_is_valid(self):
        adapter = ToolResultAdapter("tool", {"status": 200, "data": {"x": 1}})
        p = adapter.read()
        assert p.valid
        assert p.confidence == pytest.approx(0.99)
        assert p.features == {"x": 1}

    def test_error_response_is_invalid(self):
        adapter = ToolResultAdapter("tool", {"status": 500, "error": "fail"})
        p = adapter.read()
        assert not p.valid
        assert p.confidence == pytest.approx(0.0)

from dataclasses import dataclass
from typing import Callable


PerceptFilter = Callable[[Percept], bool]
PerceptTransform = Callable[[Percept], Percept]


@dataclass
class PerceptionPipeline:
    """
    A composable pipeline of filters and transforms applied to raw percepts.
    Filters drop percepts that fail a condition.
    Transforms rewrite percept fields (e.g. unit conversion, normalisation).
    """

    filters: list[PerceptFilter]
    transforms: list[PerceptTransform]

    def run(self, percept: Percept) -> Percept | None:
        """Return the transformed percept, or None if any filter rejects it."""
        for f in self.filters:
            if not f(percept):
                return None
        result = percept
        for t in self.transforms:
            result = t(result)
        return result


def min_confidence_filter(threshold: float) -> PerceptFilter:
    return lambda p: p.confidence >= threshold


def freshness_filter(max_age_ms: float) -> PerceptFilter:
    return lambda p: p.is_fresh(max_age_ms)


def celsius_to_fahrenheit_transform(p: Percept) -> Percept:
    """Example transform: unit normalisation."""
    if "temperature_c" in p.features:
        from dataclasses import replace
        new_features = dict(p.features)
        new_features["temperature_f"] = p.features["temperature_c"] * 9/5 + 32
        return replace(p, features=new_features)
    return p


pipeline = PerceptionPipeline(
    filters=[
        min_confidence_filter(0.7),
        freshness_filter(300.0),
    ],
    transforms=[celsius_to_fahrenheit_transform],
)

